def sanitize_string_input(value, max_length=200):
    """Sanitize string inputs to prevent injection attacks."""
    if value is None:
        return None
    if not isinstance(value, str):
        raise GraphQLError("Invalid input type")
    if len(value) > max_length:
        raise GraphQLError(f"Input exceeds maximum length of {max_length} characters")
    # Remove potentially dangerous characters but allow common ones
    sanitized = re.sub(r'[<>{}|\\^`]', '', value)
    return sanitized.strip()


def validate_id(value):
    """Validate that an ID is a safe alphanumeric string."""
    if value is None:
        return None
    if not isinstance(value, str):
        value = str(value)
    if not re.match(r'^[a-zA-Z0-9_-]+$', value):
        raise GraphQLError("Invalid ID format")
    if len(value) > 50:
        raise GraphQLError("ID exceeds maximum length")
    return value


def validate_pagination(first=None, offset=None):
    """Validate pagination parameters to prevent resource exhaustion."""
    max_page_size = 50
    if first is not None:
        if first < 0:
            raise GraphQLError("'first' must be non-negative")
        if first > max_page_size:
            raise GraphQLError(f"'first' cannot exceed {max_page_size}")
    if offset is not None:
        if offset < 0:
            raise GraphQLError("'offset' must be non-negative")
        if offset > 10000:
            raise GraphQLError("'offset' is too large")
    return first or 20, offset or 0


def calculate_query_depth(selection_set, current_depth=0):
    """Calculate the depth of a GraphQL query to prevent deeply nested attacks."""
    if selection_set is None:
        return current_depth
    max_depth = current_depth
    for selection in selection_set.selections:
        if hasattr(selection, 'selection_set') and selection.selection_set:
            depth = calculate_query_depth(selection.selection_set, current_depth + 1)
            max_depth = max(max_depth, depth)
    return max_depth


def calculate_query_complexity(selection_set, multiplier=1):
    """Estimate query complexity based on fields and nesting."""
    if selection_set is None:
        return 0
    complexity = 0
    for selection in selection_set.selections:
        field_complexity = multiplier
        # List fields have higher complexity
        field_name = selection.name.value if hasattr(selection, 'name') else ''
        if field_name in ('products', 'reviews', 'categories', 'allProducts', 'allCategories', 'allReviews'):
            field_complexity = multiplier * 10
        else:
            field_complexity = multiplier * 1

        complexity += field_complexity
        if hasattr(selection, 'selection_set') and selection.selection_set:
            complexity += calculate_query_complexity(selection.selection_set, multiplier * 2)
    return complexity


def check_rate_limit(client_ip):
    """Simple rate limiting by IP address."""
    now = time.time()
    # Clean old entries
    rate_limit_store[client_ip] = [
        t for t in rate_limit_store[client_ip] if now - t < RATE_LIMIT_WINDOW
    ]
    if len(rate_limit_store[client_ip]) >= RATE_LIMIT_MAX_REQUESTS:
        return False
    rate_limit_store[client_ip].append(now)
    return True


def contains_introspection(query_string):
    """Check if a query contains introspection fields."""
    introspection_patterns = [
        r'__schema',
        r'__type',
        r'__typename',  # __typename is generally safe, but we check __schema and __type
    ]
    # Only block __schema and __type, not __typename
    dangerous_patterns = [r'__schema', r'__type\b']
    for pattern in dangerous_patterns:
        if re.search(pattern, query_string, re.IGNORECASE):
            return True
    return False


def detect_batch_attack(request_data):
    """Detect and prevent query batching attacks."""
    if isinstance(request_data, list):
        max_batch_size = 5
        if len(request_data) > max_batch_size:
            return True
    return False


def detect_alias_abuse(query_string):
    """Detect excessive use of aliases which can be used for DoS."""
    # Count the number of alias patterns (word followed by colon)
    aliases = re.findall(r'\b\w+\s*:', query_string)
    max_aliases = 20
    return len(aliases) > max_aliases


