app = Flask(__name__)
app.config['MAX_CONTENT_LENGTH'] = 100 * 1024  # 100KB max request size


@app.before_request
def security_checks():
    """Global security checks before processing any request."""
    # CORS check
    origin = request.headers.get('Origin', '')
    if origin and origin not in ALLOWED_ORIGINS:
        # In development, we might be more lenient
        pass  # Log this in production

    # Content-Type check for POST requests
    if request.method == 'POST':
        content_type = request.content_type or ''
        if 'application/json' not in content_type:
            return jsonify({"errors": [{"message": "Content-Type must be application/json"}]}), 415


@app.after_request
def add_security_headers(response):
    """Add security headers to all responses."""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Content-Security-Policy'] = "default-src 'none'"
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'

    # CORS headers
    origin = request.headers.get('Origin', '')
    if origin in ALLOWED_ORIGINS:
        response.headers['Access-Control-Allow-Origin'] = origin
        response.headers['Access-Control-Allow-Methods'] = 'POST, OPTIONS'
        response.headers['Access-Control-Allow-Headers'] = 'Content-Type, Authorization'
        response.headers['Access-Control-Max-Age'] = '3600'

    return response


@app.route('/graphql', methods=['POST', 'OPTIONS'])
def graphql_endpoint():
    """Main GraphQL endpoint with comprehensive security checks."""

    # Handle CORS preflight
    if request.method == 'OPTIONS':
        return '', 204

    # Rate limiting
    client_ip = request.remote_addr
    if not check_rate_limit(client_ip):
        return jsonify({
            "errors": [{"message": "Rate limit exceeded. Please try again later."}]
        }), 429

    # Parse request body
    try:
        data = request.get_json(force=False, silent=False)
    except Exception:
        return jsonify({"errors": [{"message": "Invalid JSON in request body"}]}), 400

    if data is None:
        return jsonify({"errors": [{"message": "Request body is required"}]}), 400

    # Detect batch attacks
    if detect_batch_attack(data):
        return jsonify({
            "errors": [{"message": "Batch query limit exceeded. Maximum 5 queries per batch."}]
        }), 400

    # Handle single query or batch
    if isinstance(data, list):
        # Process batch queries
        results = []
        for query_data in data:
            result = process_single_query(query_data)
            results.append(result)
        return jsonify(results), 200
    else:
        result = process_single_query(data)
        status_code = 200 if "errors" not in result else 200  # GraphQL returns 200 even with errors
        return jsonify(result), status_code


def process_single_query(data):
    """Process a single GraphQL query with all security validations."""

    if not isinstance(data, dict):
        return {"errors": [{"message": "Invalid query format"}]}

    query = data.get('query', '')
    variables = data.get('variables') or {}
    operation_name = data.get('operationName')

    # Validate query is a string
    if not isinstance(query, str):
        return {"errors": [{"message": "Query must be a string"}]}

    # Check query length
    if len(query) > MAX_QUERY_LENGTH:
        return {"errors": [{"message": f"Query exceeds maximum length of {MAX_QUERY_LENGTH} characters"}]}

    # Check for empty query
    if not query.strip():
        return {"errors": [{"message": "Query cannot be empty"}]}

    # Introspection control
    if not INTROSPECTION_ENABLED and contains_introspection(query):
        return {"errors": [{"message": "Introspection is disabled"}]}

    # Detect alias abuse
    if detect_alias_abuse(query):
        return {"errors": [{"message": "Too many aliases in query"}]}

    # Validate variables
    if not isinstance(variables, dict):
        return {"errors": [{"message": "Variables must be an object"}]}

    # Validate operation name
    if operation_name is not None:
        if not isinstance(operation_name, str):
            return {"errors": [{"message": "Operation name must be a string"}]}
        operation_name = sanitize_string_input(operation_name, max_length=100)

    # Execute query
    try:
        result = schema.execute(
            query,
            variables=variables,
            operation_name=operation_name,
            middleware=[SecurityMiddleware()],
        )

        # Check query depth and complexity from the parsed document
        if result.document:
            for definition in result.document.definitions:
                if hasattr(definition, 'selection_set'):
                    depth = calculate_query_depth(definition.selection_set)
                    if depth > MAX_QUERY_DEPTH:
                        return {"errors": [{"message": f"Query depth {depth} exceeds maximum allowed depth of {MAX_QUERY_DEPTH}"}]}

                    complexity = calculate_query_complexity(definition.selection_set)
                    if complexity > MAX_QUERY_COMPLEXITY:
                        return {"errors": [{"message": f"Query complexity {complexity} exceeds maximum allowed complexity of {MAX_QUERY_COMPLEXITY}"}]}

        response = {}
        if result.data:
            response["data"] = result.data
        if result.errors:
            response["errors"] = [
                format_error(error) for error in result.errors
            ]
            if "data" not in response:
                response["data"] = None

        return response

    except Exception as e:
        # Don't leak internal error details
        app.logger.error(f"GraphQL execution error: {str(e)}")
        return {"errors": [{"message": "An internal error occurred while processing your query"}]}


def format_error(error):
    """Format GraphQL errors safely without leaking sensitive information."""
    formatted = {"message": str(error.message) if hasattr(error, 'message') else "An error occurred"}

    # Include locations if available (safe to expose)
    if hasattr(error, 'locations') and error.locations:
        formatted["locations"] = [
            {"line": loc.line, "column": loc.column}
            for loc in error.locations
        ]

    # Include path if available (safe to expose)
    if hasattr(error, 'path') and error.path:
        formatted["path"] = error.path

    # Do NOT include stack traces or internal details
    return formatted


